const languageOptions=[{code:'ko',label:'한국어',subtitle:'Korean'},{code:'en',label:'English',subtitle:'English'},{code:'zh',label:'中文',subtitle:'Chinese'},{code:'vi',label:'Tiếng Việt',subtitle:'Vietnamese'},{code:'ru',label:'Русский',subtitle:'Russian'},{code:'uz',label:"O'zbekcha",subtitle:'Uzbek'}];
